import java.util.ArrayList;
import java.util.List;

public class FilterUsers {
    public static class User { String name; int age; User(String n, int a) { name=n; age=a; } }
    public List<String> getAdults(List<User> users) {
        List<String> active = new ArrayList<>();
        for (User u : users) {
            if (u.age >= 18) active.add(u.name);
        }
        return active;
    }
}

