import java.util.List;

public class Stats {
    public static class Sale { String dept; double amt; }
    public double getDeptTotal(List<Sale> sales, String dept) {
        double total = 0;
        for (Sale s : sales) {
            if (s.dept.equals(dept)) total += s.amt;
        }
        return total;
    }
}
